/**
 * Token utilities for JWT generation and verification
 * Uses Web Crypto API for signing/verification
 */

// Base64 URL encode
function base64UrlEncode(buffer) {
  return btoa(String.fromCharCode(...new Uint8Array(buffer)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// Base64 URL decode
function base64UrlDecode(base64Url) {
  const padding = '='.repeat((4 - (base64Url.length % 4)) % 4);
  const base64 = (base64Url + padding).replace(/\-/g, '+').replace(/_/g, '/');
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}

/**
 * Generate a JWT token
 * @param {Object} payload - The payload to sign
 * @param {Object} env - Environment variables
 * @param {string} [expiresIn='1h'] - Token expiration time
 * @returns {Promise<string>} - The signed JWT token
 */
export async function generateToken(payload, env, expiresIn = '1h') {
  try {
    if (!env || !env.AUTH_JWT_SECRET) {
      throw new Error('JWT_SECRET is not configured in environment variables');
    }

    // Set token expiration
    const now = Math.floor(Date.now() / 1000);
    let exp;
    
    if (expiresIn) {
      const [value, unit] = expiresIn.match(/^(\d+)([smhd])$/i)?.slice(1) || [];
      if (!value || !unit) {
        throw new Error('Invalid expiresIn format. Use format like "1h", "30m", "7d"');
      }
      
      const multiplier = {
        's': 1,
        'm': 60,
        'h': 60 * 60,
        'd': 24 * 60 * 60
      }[unit.toLowerCase()];
      
      if (!multiplier) {
        throw new Error('Invalid time unit. Use s, m, h, or d');
      }
      
      exp = now + (parseInt(value) * multiplier);
    }

    // Create header
    const header = {
      alg: 'HS256', // HMAC with SHA-256
      typ: 'JWT'
    };

    // Create token payload with standard claims
    const tokenPayload = {
      ...payload,
      iat: now, // Issued at
      ...(exp && { exp }) // Expiration time
    };

    // Encode header and payload
    const encodedHeader = base64UrlEncode(
      new TextEncoder().encode(JSON.stringify(header))
    );
    
    const encodedPayload = base64UrlEncode(
      new TextEncoder().encode(JSON.stringify(tokenPayload))
    );

    // Create signature
    const signature = await crypto.subtle.sign(
      { name: 'HMAC', hash: 'SHA-256' },
      await crypto.subtle.importKey(
        'raw',
        new TextEncoder().encode(env.AUTH_JWT_SECRET),
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign', 'verify']
      ),
      new TextEncoder().encode(`${encodedHeader}.${encodedPayload}`)
    );

    const encodedSignature = base64UrlEncode(signature);

    // Combine to create JWT
    return `${encodedHeader}.${encodedPayload}.${encodedSignature}`;
  } catch (error) {
    console.error('Error generating token:', error);
    throw new Error('Failed to generate token');
  }
}

/**
 * Verify a JWT token
 * @param {string} token - The JWT token to verify
 * @param {Object} env - Environment variables
 * @returns {Promise<Object>} - The decoded token payload if valid
 */
export async function verifyToken(token, env) {
  try {
    if (!token) {
      throw new Error('No token provided');
    }

    if (!env || !env.AUTH_JWT_SECRET) {
      throw new Error('JWT_SECRET is not configured in environment variables');
    }

    const [encodedHeader, encodedPayload, encodedSignature] = token.split('.');
    
    if (!encodedHeader || !encodedPayload || !encodedSignature) {
      throw new Error('Invalid token format');
    }

    // Verify signature
    const isValid = await crypto.subtle.verify(
      { name: 'HMAC', hash: 'SHA-256' },
      await crypto.subtle.importKey(
        'raw',
        new TextEncoder().encode(env.AUTH_JWT_SECRET),
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['verify']
      ),
      base64UrlDecode(encodedSignature),
      new TextEncoder().encode(`${encodedHeader}.${encodedPayload}`)
    );

    if (!isValid) {
      throw new Error('Invalid token signature');
    }

    // Decode payload
    const payload = JSON.parse(
      new TextDecoder().decode(base64UrlDecode(encodedPayload))
    );

    // Check expiration
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < now) {
      throw new Error('Token has expired');
    }

    return payload;
  } catch (error) {
    console.error('Token verification failed:', error.message);
    throw new Error('Invalid token');
  }
}
